"use strict";(self.webpackChunkmy_doc_website=self.webpackChunkmy_doc_website||[]).push([[5418],{930:a=>{a.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"Middleware Laravel 12","metadata":{"permalink":"/en/blog/Middleware Laravel 12","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-07-02-middleware-laravel-12/index.md","source":"@site/i18n/en/docusaurus-plugin-content-blog/2025-07-02-middleware-laravel-12/index.md","title":"Memahami cara kerja Midellware pada Laravel 12","description":"Middleware menyediakan mekanisme yang mudah untuk memeriksa dan memfilter permintaan HTTP yang masuk ke aplikasi Anda. Misalnya, Laravel menyertakan middleware yang memverifikasi bahwa pengguna aplikasi Anda telah diautentikasi. Jika pengguna tidak diautentikasi, middleware akan mengarahkan pengguna ke layar login aplikasi Anda. Namun, jika pengguna diautentikasi, middleware akan memungkinkan permintaan untuk berlanjut lebih jauh ke dalam aplikasi.[1]","date":"2025-07-02T00:00:00.000Z","tags":[{"inline":false,"label":"Tutorial","permalink":"/en/blog/tags/Tutorial","description":"Tutorial peyelesian masalah dari aktivitas kerja."},{"inline":false,"label":"Laravel","permalink":"/en/blog/tags/Laravel","description":"Laravel framework related posts."},{"inline":false,"label":"Web","permalink":"/en/blog/tags/Web","description":"Web development topics."},{"inline":false,"label":"Web Software Developer","permalink":"/en/blog/tags/Web-Software-Developer","description":"Posts about web software development."}],"readingTime":6.25,"hasTruncateMarker":true,"authors":[{"name":"Jihadul Akbar","title":"Lecturer of STMIK Lombok","url":"https://github.com/jihadul4kbar","page":{"permalink":"/en/blog/authors/jihadul-4-kbar"},"socials":{"x":"https://x.com/Jihadul4kbar","github":"https://github.com/jihadul4kbar"},"imageURL":"https://jihadul4kbar.github.io/assets/img/jihadulakbar.png","key":"jihadul4kbar"}],"frontMatter":{"slug":"Middleware Laravel 12","title":"Memahami cara kerja Midellware pada Laravel 12","authors":["jihadul4kbar"],"tags":["Tutorial","Laravel","Web","Web Software Developer"]},"unlisted":false,"nextItem":{"title":"Setup widgets for monitoring port on LibreLMS","permalink":"/en/blog/Add widgets monitoring port on Libre LMS"}},"content":"Middleware menyediakan mekanisme yang mudah untuk memeriksa dan memfilter permintaan HTTP yang masuk ke aplikasi Anda. Misalnya, Laravel menyertakan middleware yang memverifikasi bahwa pengguna aplikasi Anda telah diautentikasi. Jika pengguna tidak diautentikasi, middleware akan mengarahkan pengguna ke layar login aplikasi Anda. Namun, jika pengguna diautentikasi, middleware akan memungkinkan permintaan untuk berlanjut lebih jauh ke dalam aplikasi.[1]\\n\x3c!-- truncate --\x3e\\n## Membuat User Autentikasi\\nMembuat autentikasi pengguna dengan Laravel 12, menggunakan role yang disimpan di dalam tabel users dengan tahapan sebagai berikut.\\n### 1. Menambahkan kolom role pada tabel ```user```.\\nBuka file migrasi ```database/migrations/xxxx_xx_xx_create_users_table.php```\\nTambahkan kode berikut di bagian kolom tabel:\\n```php title=\\"database/migrations/xxxx_xx_xx_create_users_table.php\\"\\n     $table->enum(\'role\', [\'admin\', \'petugas\', \'pimpinan\'])->default(\'petugas\');\\n```\\nkode ini berfungsi untuk membuat role dengan tiga lever user yakni ```admin, petugas, dan pimpinan``` dimana role secara bawaannya adalah ```petugas```.\\n\\nJalankan migrasi untuk update struktur tabel pada database :\\n```php artisan migrate:fresh```\\n```migrate:fresh``` akan menghapus semua tabel lalu menjalankan ulang semua migrasi dari awal.\\n### 2. Tambahkan Konstanta Role di ```Model User```\\n```php title=\\"app/Models/User.php\\"\\n    protected $fillable = [\\n        \'name\',\\n        \'email\',\\n        \'password\',\\n        \'role\', // Tambahkan atribut role\\n    ];\\n\\n    // Helper methods untuk check role\\n    public function isAdmin()\\n    {\\n        return $this->role === \'admin\';\\n    }\\n\\n    public function isPetugas()\\n    {\\n        return $this->role === \'petugas\';\\n    }\\n\\n    public function isPimpinan()\\n    {\\n        return $this->role === \'pimpinan\';\\n    }\\n```\\nPenjelasan\\n``` \'role\', // Tambahkan atribut role```\\nAtribut role ditambahkan agar bisa menyimpan peran pengguna, seperti admin, petugas, atau pimpinan.\\n```\\n    public function isAdmin()\\n    {\\n        return $this->role === \'admin\';\\n    }\\n```\\nFungsi ini mengembalikan true jika nilai role dari user adalah \'admin\'.\\nFungsinya untuk memudahkan pengecekan apakah user adalah admin.\\nKode ini merupakan bagian dari sistem manajemen user dengan role-based access. Dengan adanya helper method seperti isAdmin(), kamu bisa lebih mudah mengatur hak akses di controller, middleware, atau view, contohnya:\\n```\\nif (auth()->user()->isAdmin()) {\\n    // Akses khusus untuk admin\\n}\\n```\\n### 3. Membuat Middleware Role\\nJalankan perintah berikut untuk membuat middleware CheckRole\\n```\\nphp artisan make:middleware CheckRole\\n```\\nGanti isi file CheckRole dengan kode berikut\\n```php title=\\"app/Http/Middleware/CheckRole.php\\"\\n<?php\\nnamespace App\\\\Http\\\\Middleware;\\n\\nuse Closure;\\nuse Illuminate\\\\Http\\\\Request;\\nuse Illuminate\\\\Support\\\\Facades\\\\Auth;\\nuse Symfony\\\\Component\\\\HttpFoundation\\\\Response;\\n\\nclass CheckRole\\n{\\n    public function handle(Request $request, Closure $next, ...$roles)\\n    {\\n        if(!Auth::check()) {\\n            return redirect(\'/login\'); // Redirect to login if not authenticated\\n        }\\n\\n        if(!in_array(Auth::user()->role, $roles)) {\\n            abort(403, \'Unauthorized\');\\n        }\\n\\n        return $next($request);\\n    }\\n}\\n```\\nPenjelasan \\n\\n```...$roles```: Mengizinkan kita mengirim lebih dari satu role.\\n\\n```in_array(...)```: Cek apakah role user cocok dengan salah satu role yang diizinkan.\\n\\n```abort(403)```: Jika tidak cocok, akses ditolak.\\n### 4. Daftarkan Middleware Role ke Kernel\\nAgar midlleware dapat berfungsi perlu dilakukan register middleware pada ```bootstrap/app.php```\\ntambahkan kode berikut pada pada file app.php\\n```php title=\\"bootstrap/app.php\\"\\n<?php\\nuse App\\\\Http\\\\Middleware\\\\CheckRole;\\nuse Illuminate\\\\Foundation\\\\Application;\\nuse Illuminate\\\\Foundation\\\\Configuration\\\\Exceptions;\\nuse Illuminate\\\\Foundation\\\\Configuration\\\\Middleware;\\n\\nreturn Application::configure(basePath: dirname(__DIR__))\\n    ->withRouting(\\n        web: __DIR__.\'/../routes/web.php\',\\n        commands: __DIR__.\'/../routes/console.php\',\\n        health: \'/up\',\\n    )\\n    ->withMiddleware(function (Middleware $middleware): void {\\n        // Register alias middleware (untuk digunakan pada route)\\n        $middleware->alias([\'role\' => CheckRole::class]);\\n    })\\n    ->withExceptions(function (Exceptions $exceptions): void {\\n        //\\n    })->create();\\n```\\nperhatikan pada bagian ``` $middleware->alias([\'role\' => CheckRole::class]);```\\ndigunakan untuk memberi nama ```role``` untuk middleware kita agar bisa digunakan dalam route seperti``` middleware(\'role:admin\')```.\\n\\n### 5. Routing Berdasarkan Role\\n``` php title=\\"routes/web.php\\"\\nuse Illuminate\\\\Support\\\\Facades\\\\Route;\\n\\nRoute::get(\'/\', function () {\\n    return view(\'welcome\');\\n});\\n\\n// Semua user yang sudah login\\nRoute::middleware([\'auth\'])->group(function () {\\n    Route::get(\'/dashboard\', function () {\\n        return view(\'dashboard\');\\n    });\\n    // Khusus admin\\n    Route::middleware([\'role:admin\'])->group(function () {\\n        Route::get(\'/admin\', function () {\\n            return \\"Selamat datang Admin!\\";\\n        });\\n       // Route::resource(\'user\', UserController::class);\\n    });\\n    // Khusus petugas biasa\\n    Route::middleware([\'role:petugas\'])->group(function () {\\n        Route::get(\'/petugas\', function () {\\n            return \\"Selamat datang petugas!\\";\\n        });\\n        //Route::resource(\'/petugas\', FiturPetugasController::class);\\n    });\\n    // Khusus pimpinan biasa\\n    Route::middleware([\'role:Pimpinan\'])->group(function () {\\n        Route::get(\'/pimpinan\', function () {\\n            return \\"Selamat datang Pimpinan!\\";\\n        });\\n        //Route::resource(\'/lapaoran\', LaporanController::class);\\n    });\\n    // Khusus admin dan petugas biasa\\n    Route::middleware([\'role:admin,petugas\'])->group(function () {\\n        Route::get(\'/transaksi\', function () {\\n            return \\"Selamat datang petugas atau admin!\\";\\n        });\\n        //Route::resource(\'/transaksi\', TransaksiController::class);\\n    });\\n});\\n\\n```\\nPenjelasan:\\n\\nMiddleware ```auth:``` Pastikan hanya user login yang bisa akses.\\n\\nMiddleware ```role:admin```: Hanya bisa diakses user yang role-nya \'admin\'.\\n\\nMiddleware ```role:petugas```: Hanya untuk user dengan role petugas.\\n\\nMiddleware ```role:pimpinan```: Hanya untuk user dengan role pimpinan.\\n\\nMiddleware ```role:admin,petugas```: Hanya untuk user role admin dan petugas.\\n\\n### 6. Menambah user ke dalam tabel user berdasarkan role\\njalankan perintah pada terminal \\n```php\\nphp artisan tinker\\n```\\n\\nselanjutnya tambahkan user dengan perintah berikut \\n```php\\nDB::table(\'users\')->insert([\'name\' => \'Admin\',\'email\' => \'admin@contoh.com\',\'password\' => Hash::make(\'12345678\'),\'role\' => \'admin\']);\\n```\\nperintah untuk menambah user dengan nama ```Admin, email admin@contoh.com, password 12345678 dan role admin```\\n\\n```php\\nDB::table(\'users\')->insert([\'name\' => \'Petugas\',\'email\' => \'petugas@contoh.com\',\'password\' => Hash::make(\'12345678\'),\'role\' => \'petugas\']);\\n```\\nperintah untuk menambah user dengan nama ```Petugas, email petugas@contoh.com, password 12345678 dan role petugas```\\n```php\\nDB::table(\'users\')->insert([\'name\' => \'Pimpinan\',\'email\' => \'pimpinan@contoh.com\',\'password\' => Hash::make(\'12345678\'),\'role\' => \'pimpinan\']);\\n```\\nperintah untuk menambah user dengan nama ```Pimpinan, email pimpinan@contoh.com, password 12345678 dan role pimpinan```\\n\\n### 7. Membuat Login dan Logout \\njalankan perintah berikut untuk membuat ```AuthController.php``` pada folder Auth\\n```\\nphp artisan make:controller Auth/AuthController\\n```\\nsetelah berhasil maka buka file tersebut dan isi dengan kode berikut\\n```php title=\\"app\\\\Http\\\\Controllers\\\\Auth\\\\AuthController.php\\"\\n<?php\\nnamespace App\\\\Http\\\\Controllers\\\\Auth;\\n\\nuse Illuminate\\\\Http\\\\Request;\\nuse App\\\\Http\\\\Requests\\\\LoginRequest;\\nuse App\\\\Http\\\\Controllers\\\\Controller;\\nuse Illuminate\\\\Support\\\\Facades\\\\Auth;\\n\\nclass AuthController extends Controller\\n{\\n    public function showLoginForm()\\n    {\\n        return view(\'auth.login\');\\n    }\\n\\n    public function login(Request $request)\\n    {\\n        // Validasi input\\n        $credentials = $request->validate([\\n            \'email\' => \'required|email\',\\n            \'password\' => \'required|min:6\',\\n        ]);\\n\\n        // Coba login\\n        if (Auth::attempt($credentials)) {\\n            $user = Auth::user();\\n            return redirect()->route(\'dashboard\'); // Redirect ke dashboard setelah login\\n        }\\n\\n        // Jika gagal, kembalikan dengan error\\n        return back()->withErrors([\\n            \'email\' => \'Email atau password salah.\',\\n        ])->withInput();\\n    }\\n    public function logout(Request $request)\\n    {\\n        Auth::logout();\\n        $request->session()->invalidate();\\n        $request->session()->regenerateToken();\\n        return redirect(\'/login\')->with(\'status\', \'Anda telah berhasil logout.\');\\n    }\\n}\\n\\n```\\nmembuat halaman login pada folder auth dengan nama login.blade.php\\n\\n```php title=\\"resources\\\\views\\\\auth\\\\login.blade.php\\"\\n      <form action=\\"{{ route(\'login\') }}\\" method=\\"POST\\">\\n        @csrf\\n          <input type=\\"email\\" name=\\"email\\" required autocomplete=\\"email\\" autofocus placeholder=\\"Email\\">\\n          @error(\'email\')\\n              {{ $message }}\\n          @enderror\\n          <input type=\\"password\\" name=\\"password\\" placeholder=\\"Password\\" required autocomplete=\\"current-password\\">\\n          @error(\'password\')\\n              {{ $message }}\\n          @enderror\\n            <button type=\\"submit\\">Sign In</button>\\n      </form>\\n```\\nSelanjutnya membuat halaman dashbord.blade.php \\n```php title=\\"resources\\\\views\\\\dashbord.blade.php\\"\\n<h3>Selamat datang {{ auth()->user()->name }}</h3><br>\\n      Role : {{ auth()->user()->role }}\\n\\n\\n\\n\\n  @if(auth()->user()->isAdmin())\\n  <p>Menu Untuk Admin</p><br>\\n    <a href=\\"\\">Menu Untuk Admin</a>\\n  @endif\\n        \\n  @if(auth()->user()->isPetugas())\\n    <p>Menu Untuk Pegugas</p><br>\\n    <a href=\\"\\">Menu Untuk Petugas</a>\\n  @endif\\n\\n  @if(auth()->user()->isPimpinan())\\n    <p>Menu Untuk Pimpinan</p><br>\\n    <a href=\\"\\">Menu Untuk pimpinan</a>\\n  @endif\\n\\n<br>\\n    <form method=\\"POST\\" action=\\"{{ route(\'logout\') }}\\">\\n        @csrf\\n        <button type=\\"submit\\">Logout</button>\\n    </form>\\n\\n```\\n### 8. Route Lengkap\\nberikut route lengkapnya \\n``` php title=\\"routes/web.php\\"\\nuse Illuminate\\\\Support\\\\Facades\\\\Route;\\nuse App\\\\Http\\\\Controllers\\\\Auth\\\\AuthController;\\n\\nRoute::get(\'/\', function () {\\n    return view(\'welcome\');\\n});\\n// Auth Routes\\nRoute::controller(AuthController::class)->group(function () {\\n    Route::get(\'login\', \'showLoginForm\')->name(\'login\');\\n    Route::post(\'login\', \'login\');\\n    Route::post(\'logout\', \'logout\')->name(\'logout\');\\n});\\n// Semua user yang sudah login\\nRoute::middleware([\'auth\'])->group(function () {\\n    Route::get(\'/dashboard\', function () {\\n        return view(\'dashboard\');\\n    })->name(\'dashboard\');\\n    // Khusus admin\\n    Route::middleware([\'role:admin\'])->group(function () {\\n        Route::get(\'/admin\', function () {\\n            return \\"Selamat datang Admin!\\";\\n        });\\n       // Route::resource(\'user\', UserController::class);\\n    });\\n    // Khusus petugas biasa\\n    Route::middleware([\'role:petugas\'])->group(function () {\\n        Route::get(\'/petugas\', function () {\\n            return \\"Selamat datang petugas!\\";\\n        });\\n        //Route::resource(\'/petugas\', FiturPetugasController::class);\\n    });\\n    // Khusus pimpinan biasa\\n    Route::middleware([\'role:Pimpinan\'])->group(function () {\\n        Route::get(\'/pimpinan\', function () {\\n            return \\"Selamat datang Pimpinan!\\";\\n        });\\n        //Route::resource(\'/lapaoran\', LaporanController::class);\\n    });\\n    // Khusus admin dan petugas biasa\\n    Route::middleware([\'role:admin,petugas\'])->group(function () {\\n        Route::get(\'/transaksi\', function () {\\n            return \\"Selamat datang petugas atau admin!\\";\\n        });\\n        //Route::resource(\'/transaksi\', TransaksiController::class);\\n    });\\n});\\n```\\n## Refrensi\\n[1] https://laravel.com/docs/12.x/middleware"},{"id":"Add widgets monitoring port on Libre LMS","metadata":{"permalink":"/en/blog/Add widgets monitoring port on Libre LMS","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-01-18-add-widget-monitoring-librelms/index.md","source":"@site/i18n/en/docusaurus-plugin-content-blog/2025-01-18-add-widget-monitoring-librelms/index.md","title":"Setup widgets for monitoring port on LibreLMS","description":"Docusaurus blogging features are powered by the blog plugin.","date":"2025-01-18T00:00:00.000Z","tags":[{"inline":false,"label":"tutorial","permalink":"/en/blog/tags/tutorial","description":"Tutorial posts."},{"inline":false,"label":"libreLMS","permalink":"/en/blog/tags/libreLMS","description":"libreLMS learning management system."},{"inline":false,"label":"Network","permalink":"/en/blog/tags/Network","description":"Networking topics."}],"readingTime":0.54,"hasTruncateMarker":true,"authors":[{"name":"Jihadul Akbar","title":"Lecturer of STMIK Lombok","url":"https://github.com/jihadul4kbar","page":{"permalink":"/en/blog/authors/jihadul-4-kbar"},"socials":{"x":"https://x.com/Jihadul4kbar","github":"https://github.com/jihadul4kbar"},"imageURL":"https://jihadul4kbar.github.io/assets/img/jihadulakbar.png","key":"jihadul4kbar"},{"name":"Hadi Wijaya","title":"Lombok Cyber Community Organizer","url":"https://github.com/hadyanwijaya","page":{"permalink":"/en/blog/authors/hadyanwijaya"},"socials":{"x":"https://x.com/hadyanwijaya","github":"https://github.com/hadyanwijaya"},"imageURL":"https://avatars.githubusercontent.com/u/11438225?v=4","key":"hadyanwijaya"},{"name":"Hairul Fahmi","title":"Lecturer of STMIK Lombok","url":"https://github.com/hairulfhm","page":{"permalink":"/en/blog/authors/hairulfhm"},"socials":{"x":"https://x.com/hairulfhm","github":"https://github.com/hairulfhm"},"imageURL":"https://avatars.githubusercontent.com/u/28390561?v=4","key":"hairulfhm"}],"frontMatter":{"slug":"Add widgets monitoring port on Libre LMS","title":"Setup widgets for monitoring port on LibreLMS","authors":["jihadul4kbar","hadyanwijaya","hairulfhm"],"tags":["tutorial","libreLMS","Network"]},"unlisted":false,"prevItem":{"title":"Memahami cara kerja Midellware pada Laravel 12","permalink":"/en/blog/Middleware Laravel 12"}},"content":"[Docusaurus blogging features](https://docusaurus.io/docs/blog) are powered by the [blog plugin](https://docusaurus.io/docs/api/plugins/@docusaurus/plugin-content-blog).\\n\\nHere are a few tips you might find useful.\\n\\n\x3c!-- truncate --\x3e\\n\\nSimply add Markdown files (or folders) to the `blog` directory.\\n\\nRegular blog authors can be added to `authors.yml`.\\n\\nThe blog post date can be extracted from filenames, such as:\\n\\n- `2019-05-30-welcome.md`\\n- `2019-05-30-welcome/index.md`\\n\\nA blog post folder can be convenient to co-locate blog post images:\\n\\n\\nThe blog supports tags as well!\\n\\n**And if you don\'t want a blog**: just delete this directory, and use `blog: false` in your Docusaurus config."}]}}')}}]);